const o=()=>localStorage.getItem("dehbi_token"),n={get:async e=>{const r=await fetch(`/api${e}`);if(!r.ok)throw new Error("Erreur de chargement");return r.json()},post:async(e,r)=>{const t=await fetch(`/api${e}`,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${o()}`},body:JSON.stringify(r)});if(!t.ok)throw new Error("Erreur de création");return t.json()},put:async(e,r)=>{const t=await fetch(`/api${e}`,{method:"PUT",headers:{"Content-Type":"application/json",Authorization:`Bearer ${o()}`},body:JSON.stringify(r)});if(!t.ok)throw new Error("Erreur de mise à jour");return t.json()},del:async e=>{const r=await fetch(`/api${e}`,{method:"DELETE",headers:{Authorization:`Bearer ${o()}`}});if(!r.ok)throw new Error("Erreur de suppression");return r.json()}};export{n as a};
